mapper.select:
select category.*, user.name as userName from category
left join user on category.user_id = user.id

     and category.id = #{id}
     and category.img like concat('%', #{img}, '%')
     and category.name like concat('%', #{name}, '%')
     and category.user_id = #{userId}
     and user.name like concat('%', #{userName}, '%')
     and category.status_radio like concat('%', #{statusRadio}, '%')
     and category.time like concat('%', #{time}, '%')
     and category.role_radio like concat('%', #{roleRadio}, '%')
     and category.view_count = #{viewCount}
     and category.collect_count = #{collectCount}
     and category.hot_point = #{hotPoint}

order by time desc, id desc
